export enum Category {
  POLITICS = 'Politics',
  STATE = 'State News',
  LOCAL = 'Local/District',
  JOBS = 'Jobs & Careers',
  CRIME = 'Crime',
  RTI = 'RTI & Legal',
  VIDEO = 'Video News',
}

export interface Article {
  id: string;
