}

import { GoogleGenAI } from "@google/genai";

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.warn("API Key is missing. Please ensure process.env.API_KEY is set.");
    return null;
  }
  return new GoogleGenAI({ apiKey });
};

export const draftNewsReport = async (rawNotes: string, location: string): Promise<string> => {
  const ai = getAiClient();
  if (!ai) return "Error: API Key missing. Cannot generate report.";

  try {
    const prompt = `
      You are a senior editor for 'Khabar Kal Tak', a prestigious news agency in Chhattisgarh.
      Turn the following raw notes from a citizen reporter into a professional news article.

      Location: ${location}
      Raw Notes: "${rawNotes}"

      Requirements:
      1. Headline: Catchy and professional.
      2. Body: Inverted pyramid structure (most important info first).
      3. Tone: Objective, journalistic, and urgent if needed.
      4. Length: Around 150-200 words.
      5. Language: English (Indian context).

      Format the output as simple text with a clear Headline followed by the body.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Failed to generate report content.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Error: Failed to connect to the news desk AI. Please try again later.";
  }
};

