import { Article } from '../types';
import { MOCK_ARTICLES } from '../constants';

const STORAGE_KEY = 'kkt_articles_db_v1';

// Initialize storage with mock data if empty
const initStorage = () => {
  const stored = localStorage.getItem(STORAGE_KEY);
  if (!stored) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(MOCK_ARTICLES));
  }
};

export const getArticles = (): Article[] => {
  initStorage();
  const stored = localStorage.getItem(STORAGE_KEY);
  return stored ? JSON.parse(stored) : [];
};

export const getArticleById = (id: string): Article | undefined => {
  const articles = getArticles();
  return articles.find(a => a.id === id);
};

export const saveArticle = (article: Article): void => {
  const articles = getArticles();
  const index = articles.findIndex(a => a.id === article.id);

  if (index >= 0) {
    // Update existing
    articles[index] = article;
  } else {
    // Create new (add to top)
    articles.unshift(article);
  }

  localStorage.setItem(STORAGE_KEY, JSON.stringify(articles));
};

export const deleteArticle = (id: string): void => {
  const articles = getArticles().filter(a => a.id !== id);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(articles));
};

// Helper to reset data if things get messy
export const resetToDefaults = () => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(MOCK_ARTICLES));
  window.location.reload();
};

