import { Article, BreakingNews, SiteSettings } from '../types';
import { MOCK_ARTICLES, MOCK_BREAKING_NEWS, DEFAULT_SETTINGS } from '../constants';

const KEYS = {
  ARTICLES: 'kkt_articles_v1',
  BREAKING: 'kkt_breaking_v1',
  SETTINGS: 'kkt_settings_v1',
};

// --- Helpers ---
const get = <T>(key: string, defaultVal: T): T => {
  try {
    const stored = localStorage.getItem(key);
    return stored ? JSON.parse(stored) : defaultVal;
  } catch (e) {
    console.error(`Error reading ${key}`, e);
    return defaultVal;
  }
};

const set = <T>(key: string, val: T): void => {
  localStorage.setItem(key, JSON.stringify(val));
};

// --- Articles ---
export const getArticles = (): Article[] => {
  // If nothing in storage, save defaults first to ensure they exist for the admin
  const stored = localStorage.getItem(KEYS.ARTICLES);
  if (!stored) {
    set(KEYS.ARTICLES, MOCK_ARTICLES);
    return MOCK_ARTICLES;
  }
  return JSON.parse(stored);
};

export const getArticleById = (id: string): Article | undefined => {
  return getArticles().find(a => a.id === id);
};

export const saveArticle = (article: Article): void => {
  const articles = getArticles();
  const index = articles.findIndex(a => a.id === article.id);

  if (index >= 0) {
    articles[index] = article;
  } else {
    articles.unshift(article);
  }
  set(KEYS.ARTICLES, articles);
};

export const deleteArticle = (id: string): void => {
  const articles = getArticles().filter(a => a.id !== id);
  set(KEYS.ARTICLES, articles);
};

// --- Breaking News ---
export const getBreakingNews = (): BreakingNews[] => {
  const stored = localStorage.getItem(KEYS.BREAKING);
  if (!stored) {
    set(KEYS.BREAKING, MOCK_BREAKING_NEWS);
    return MOCK_BREAKING_NEWS;
  }
  return JSON.parse(stored);
};

export const saveBreakingNews = (newsList: BreakingNews[]): void => {
  set(KEYS.BREAKING, newsList);
};

// --- Site Settings ---
export const getSettings = (): SiteSettings => {
  const stored = localStorage.getItem(KEYS.SETTINGS);
  if (!stored) {
    set(KEYS.SETTINGS, DEFAULT_SETTINGS);
    return DEFAULT_SETTINGS;
  }
  return JSON.parse(stored);
};

export const saveSettings = (settings: SiteSettings): void => {
  set(KEYS.SETTINGS, settings);
};

// --- Reset ---
export const resetToDefaults = () => {
  localStorage.removeItem(KEYS.ARTICLES);
  localStorage.removeItem(KEYS.BREAKING);
  localStorage.removeItem(KEYS.SETTINGS);
  window.location.reload();
};

